const initReadingTime = () => {
  const textHolder = document.querySelector('.js-expected-read-time');
  const article = document.querySelector('.js-article');

  if (!textHolder || !article) return;

  const articleText = article.innerText,
        wpm = 150,
        words = articleText.trim().split(/\s+/).length,
        time = Math.ceil(words / wpm);

  textHolder.innerText = time;
};

export default initReadingTime;
