import { Bootstrap } from '../main.js';

export const initActiveClassForHamburger = () => {
  const offcanvasMenu = document.querySelector('.js-offcanvas-menu');

  if (!offcanvasMenu) return;

  offcanvasMenu.addEventListener('show.bs.offcanvas', function(e) {
    e.relatedTarget.classList.add('active');
  });

  offcanvasMenu.addEventListener('hide.bs.offcanvas', function(e) {
    const relatedTarget = document.querySelectorAll('a[href="#' + e.target.id + '"], [data-bs-target="#' + e.target.id + '"]')[0];

    if (typeof (relatedTarget) != 'undefined' && relatedTarget != null) {
      relatedTarget.classList.remove('active');
    }
  });
};

export const initCloseOffcanvasMenuForAnchors = () => {
  const offcanvasMenu = document.querySelector('.js-offcanvas-menu');

  if (!offcanvasMenu) return;

  const anchors = offcanvasMenu.querySelectorAll('a[href*="#"]:not([href="#"]):not(.js-no-scroll)');

  if (!anchors.length) return;

  const offcanvasMenuInstance = Bootstrap.Offcanvas.getOrCreateInstance(offcanvasMenu);

  anchors.forEach(anchor => {
    anchor.addEventListener('click', () => {
      offcanvasMenuInstance.hide();
    });
  });
};
