import Cookies from 'js-cookie';

import { Bootstrap } from '../main.js';

const initModalUnlockFullAccess = () => {
  const investigatorSingleLinks = document.querySelectorAll('.js-investigator-single-link');
  const modalUnlockFullAccess = document.querySelector('#modal-unlock-full-access');

  if (!investigatorSingleLinks.length || !modalUnlockFullAccess) return;

  investigatorSingleLinks.forEach(link => {
    link.addEventListener('click', e => {
      const isUnlocked = Cookies.get('is-investigator-page-unlocked') === 'true';

      if (!isUnlocked) {
        e.preventDefault();

        const modal = new Bootstrap.Modal(modalUnlockFullAccess);

        modal.show();

        // Cookies.set('is-investigator-page-unlocked', 'true', { expires: 365 });
      }
    });
  });
};

export default initModalUnlockFullAccess;
