const initScrollingProgress = () => {
  const scrollingProgressItem = document.querySelector('.js-scrolling-progress'),
        scrollingProgressContent = document.querySelector('.js-scrolling-progress-content'),
        header = document.querySelector('.js-header');

  function scrollingProgress() {
    const winScroll = document.body.scrollTop || document.documentElement.scrollTop;

    let scrollBarWidth;

    if (scrollingProgressContent) {
      const contentHeight = scrollingProgressContent.offsetHeight,
            headerCompensation = header ? header.offsetHeight : 0,
            contentOffsetTop = scrollingProgressContent.offsetTop - headerCompensation,
            diff = winScroll - contentOffsetTop;

      if (diff <= 0) {
        scrollBarWidth = 0;
      } else {
        if ((winScroll) <= (contentOffsetTop + contentHeight)) {
          scrollBarWidth = (diff / contentHeight) * 100;
        } else {
          scrollBarWidth = 100;
        }
      }
    } else {
      const documentHeight = document.documentElement.scrollHeight - window.innerHeight;

      scrollBarWidth = (winScroll / documentHeight) * 100;
    }

    scrollingProgressItem.style.width = scrollBarWidth + '%';
  }

  if (scrollingProgressItem) {
    window.addEventListener('scroll', function() {
      scrollingProgress();
    });
  }
};

export default initScrollingProgress;
