const initSmoothAnchorLinks = () => {
  let animationComplete = true;
  const anchorLinks = document.querySelectorAll('a[href*="#"]:not([href="#"]):not(.js-no-scroll):not([data-bs-toggle="modal"])');
  const urlHash = window.location.href.split('#')[1];
  const urlHashElement = urlHash ? document.querySelector('#' + urlHash) : null;

  const getHeaderActiveHeight = () => {
    const temp = document.createElement('div');

    temp.style.cssText = 'position:absolute;visibility:hidden;height:var(--header-height-active)';
    document.body.appendChild(temp);

    const value = temp.offsetHeight;

    document.body.removeChild(temp);

    return value;
  };

  const getItemDistanceFromTop = element => {
    if (!element) return;

    const header = document.querySelector('.js-header.fixed-top');
    const headerOffset = header ? (window.scrollY > 10 ? header.offsetHeight : getHeaderActiveHeight()) : 0;
    const distanceFromTop = element.offsetTop - headerOffset + 1;

    return distanceFromTop;
  };

  const smoothScrollTo = (to, duration = 1000, callback) => {
    if (!animationComplete) return;

    animationComplete = false;

    const start = window.scrollY || window.pageYOffset;
    const startTime = performance.now();

    function scrollStep(currentTime) {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / duration, 1);

      const ease = progress < 0.5
        ? (4 * progress * progress * progress)
        : (1 - (Math.pow(((-2 * progress) + 2), 3) / 2));

      window.scrollTo(0, (start + ((to - start) * ease)));

      if (elapsed < duration) {
        requestAnimationFrame(scrollStep);
      } else {
        animationComplete = true;

        if (callback) callback();
      }
    }

    requestAnimationFrame(scrollStep);
  };

  anchorLinks.forEach(link => {
    link.addEventListener('click', function() {
      const href = this.getAttribute('href');
      const idOfElement = href.includes('#') ? '#' + href.split('#')[1] : href;
      const targetElement = document.querySelector(idOfElement);
      const distanceFromTop = getItemDistanceFromTop(targetElement);

      if (!distanceFromTop) return;

      smoothScrollTo(distanceFromTop);
    });
  });

  if (urlHash && urlHashElement) {
    setTimeout(function() {
      const distanceFromTop = getItemDistanceFromTop(urlHashElement);

      if (!distanceFromTop) return;

      smoothScrollTo(distanceFromTop);
    }, 1000);
  }
};

export default initSmoothAnchorLinks;
