import Swiper from 'swiper';
import {
  Navigation, Pagination, EffectCoverflow, Autoplay
} from 'swiper/modules';

import { breakpoints } from '@utils/constants';

const initSliders = () => {
  const sliderInvestigatorShowcase = new Swiper('.js-slider-investigator-showcase', {
    modules: [Navigation, Pagination, EffectCoverflow],
    effect: 'coverflow',
    centeredSlides: true,
    createElements: true,
    slidesPerView: 'auto',
    coverflowEffect: {
      rotate: 0,
      modifier: 1,
      slideShadows: false,
    },
    speed: 600,
    loop: true,

    navigation: {
      addIcons: false,
      enabled: true,
    },

    pagination: {
      clickable: true,
      dynamicBullets: true,
      dynamicMainBullets: 5,
      enabled: true,
    },

    breakpoints: {
      0: {
        allowTouchMove: true,
        navigation: { enabled: false },
        coverflowEffect: {
          stretch: '68%',
          depth: 380,
        },
      },
      [breakpoints.sm]: {
        allowTouchMove: false,
        navigation: { enabled: false },
        coverflowEffect: {
          stretch: '45%',
          depth: 380,
        },
      },
      [breakpoints.md]: {
        allowTouchMove: false,
        navigation: { enabled: true },
        coverflowEffect: {
          stretch: '45%',
          depth: 380,
        },
      },
    },
  });

  const sliderLogos = new Swiper('.js-slider-logos', {
    modules: [Autoplay],
    createElements: true,
    slidesPerView: 2,
    loop: true,
    speed: 5000,
    allowTouchMove: false,
    autoplay: {
      delay: 1,
      disableOnInteraction: false
    },

    breakpoints: {
      0: {
        slidesPerView: 2,
      },
      [breakpoints.xs]: {
        slidesPerView: 3,
      },
      [breakpoints.md]: {
        slidesPerView: 4,
      },
      [breakpoints.lg]: {
        slidesPerView: 6,
      },
      [breakpoints.xl]: {
        slidesPerView: 8,
      },
    },

    on: {
      init: function(swiper) {
        if (swiper.slides.length < swiper.params.slidesPerView) {
          swiper.el.classList.add('swiper-not-active');
        } else {
          swiper.el.classList.remove('swiper-not-active');
        }
      },
      breakpoint: function(swiper) {
        if (swiper.slides.length < swiper.params.slidesPerView) {
          swiper.el.classList.add('swiper-not-active');
        } else {
          swiper.el.classList.remove('swiper-not-active');
        }
      }
    },
  });
};

export default initSliders;
